INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-8b7f1efc-moex-00387', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '有關內政部警政署「警察勤務區訪查作業規定」，下列敘述何者錯誤？', '["治安顧慮人口自刑期執行完畢或假釋出獄後，每個月查訪一次，查訪三年，期滿改列一般 人口；必要時，得增加查訪次數", "記事人口於登記或通知後開始查訪，查訪次數依各警察局刑事業務主管單位規劃辦理", "記事人口增減時，由業務主管單位循業務系統通知相關單位及人員辦理", "村（里）鄰長每月聯繫拜訪一次以上；其他諮詢對象及一般人口得視需要實施訪查"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00388', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依現行警察勤務區訪查作業規定，警察勤務區實施訪查應注意之事項，下列敘述何者不正確？', '["實施訪查應尊重當事人權益，以誠實信用方法為之，符合比例原則，並應嚴守行政中立， 依法公正執行職務", "發覺可疑犯罪跡象或無法實施查訪時，得以間接方式觀察並記錄可疑處後，提供所長列為 勤務規劃重點", "治安顧慮人口、記事人口、一般人口或諮詢對象拒絕查訪時，得以側訪或其他方式實施", "發現有犯罪情事時，應依刑事訴訟法、刑法及相關法規辦理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00389', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '有關警勤區訪查時間暨執行方式，下列敘述何者正確？', '["警勤區每月應編排十二小時以上訪查時數，其基準由分駐（派出）所所長定之，得視勤務 需要檢討調整，並送警察分局備查", "實施警勤區訪查前，應於勤查系統預擬日誌表，送分局核准後實施", "警勤區訪查以單警個別查察為原則；必要時得以聯合查察或座談會方式實施", "訪查時應出示服務證表明身分，並告知訪查目的，但不硬性規定穿著制服；經由所長核准 以社區座談會方式實施訪查者，於訪查日三日前以書面通知受訪查者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00390', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依現行治安顧慮人口查訪辦法之規定，下列何者為警察職權行使法第15條第1項規定，得 定期實施查訪之對象？', '["曾犯森林法第50條第1項竊取森林主、副產物罪者", "曾犯槍砲彈藥刀械管制條例所定製造管制刀械之罪者", "曾犯刑法第278條使人重傷罪者", "曾犯刑法第273條當場激於義憤而殺人罪者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00391', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '有關治安顧慮人口查訪辦法與警察遴選第三人蒐集資料辦法之相關敘述，下列何者正確？', '["治安顧慮人口查訪辦法依警察職權行使法第15條第3項規定訂定之", "警察遴選第三人 蒐集資料辦法依警察職權行使法第12條第4項規定訂定之", "警察遴選第三人及第三人蒐 集之資料，應注意保密，專案建檔，並指定專人依文書機密法管理之", "治安顧慮人口由居 住地警察機關每個月實施查訪一次。必要時，得增加查訪次數"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00392', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依據內政部警政署警察機關分駐（派出）所常用勤務執行程序彙編，有關警察人員受理失蹤 人口緊急查尋案件，下列敘述何者錯誤？', '["緊急查尋案件涉及刑事案件時，應立即陳（通）報刑事單位處理", "未滿7歲兒童失蹤案件，於24小時內未尋獲者，經查疑涉刑案者，應向勤務指揮中心通 報，俾利勤務派遣及案件管制", "未尋獲案件戶籍地派出所所長應定期訪查家屬", "M-Police 相片比對功能係輔助驗證身分之最後手段，蒐集當事人影像以使用 M-Police 相 片比對系統前，須告知當事人事由，並經當事人同意"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00393', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '警察人員受理報案，有關e化管理作業之執行，下列敘述何者錯誤？', '["警察單位受理各類案件後，遇有相關其他行政單位應辦事項，基於為民服務，後續處置仍 應由警察單位迅速依程序辦理", "應以線上版作業為原則，遇有網路連線或系統故障時，以單機版進行作業；受理報案於單 機版輸登列印完成及交付民眾後，需啟動連線上傳檔案", "各作業系統因天災或不可抗力等因素，無法於線上受理報案時，得先以人工製單方式交予 民眾，並於系統恢復使用 24 小時內補登後，列印電腦表單併人工表單陳報所屬上級機關 （構）", "受理民眾報案如處置不當、未轉介或刑案匿報、遲報、虛報等不當情事，依各級警察機關 處理刑案逐級報告紀律規定辦理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00394', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '駕駛動力交通工具，下列何者不適用「刑法」第185條之3規定？', '["血液中酒精濃度達百分之0.05以上", "血液中酒精濃度達百分之0.03以上", "有其他情事足認服用酒類或其他相類之物，致不能安全駕駛", "服用毒品、麻醉藥品，致不能安全駕駛"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00395', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依據「處理跟蹤騷擾案件作業程序」，有關核發書面告誡及聲請保護令之敘述，下列何者 錯誤？', '["涉及「家庭暴力防治法」之跟蹤騷擾案件，應依「跟蹤騷擾防制法」聲請跟踨騷擾保護令， 不適用家暴保護令聲請程序", "已核發書面告誡或保護令之案件，再有跟蹤騷擾行為時，不再核發書面告誡", "刑案偵查程序與書面告誡審查、核發程序併行", "書面告誡送達生效後，核發分局應以書面通知被害人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00396', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '下列汽車駕駛人之行為，何者非屬道路交通管理處罰條例第7條之2規定，當場不能或不宜 攔截製單舉發者，得逕行舉發之情形？', '["闖紅燈或平交道", "經以科學儀器取得證據資料證明其行為違規", "以手持方式使用行動電話、電腦或其他相類功能裝置進行撥接、通話、數據通訊或其他有 礙駕駛安全之行為者", "違規停車或搶越行人穿越道，經各級學校交通服務隊現場導護人員簽證檢舉"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
